def calculate_max_drawdown(price_series):
    cumulative_max = []
    drawdown_series = []

    for price in price_series:
        if not cumulative_max:
            cumulative_max.append(price)
        else:
            cumulative_max.append(max(cumulative_max[-1], price))

    for i in range(len(price_series)):
        drawdown_series.append((cumulative_max[i] - price_series[i]) / cumulative_max[i])

    return max(drawdown_series) if drawdown_series else 0

import numpy as np
from scipy.stats import norm

def black_scholes(S, K, T, r, sigma, option_type='call'):
    d1 = (np.log(S / K) + (r + 0.5 * sigma ** 2) * T) / (sigma * np.sqrt(T))
    d2 = d1 - sigma * np.sqrt(T)
    if option_type == 'call':
        return S * norm.cdf(d1) - K * np.exp(-r * T) * norm.cdf(d2)
    else:
        return K * np.exp(-r * T) * norm.cdf(-d2) - S * norm.cdf(-d1)

def black_scholes_vega(S, K, T, r, sigma):
    d1 = (np.log(S / K) + (r + 0.5 * sigma ** 2) * T) / (sigma * np.sqrt(T))
    return S * norm.pdf(d1) * np.sqrt(T)

def implied_volatility(S, K, T, r, market_price, option_type='call', tol=1e-5, max_iter=100):
    sigma = 0.20  # initial guess for volatility
    for _ in range(max_iter):
        price = black_scholes(S, K, T, r, sigma, option_type)
        vega = black_scholes_vega(S, K, T, r, sigma)
        diff = market_price - price
        if abs(diff) < tol:
            return sigma
        sigma += diff / vega
    return sigma

